// Worked focus: httpsts-http1-http2-http3-boundary — Distinguish HTTP/1.1, Node HTTP/2 compatibility behavior, ALPN, TLS, upgrades, CONNECT, and the explicit external boundary for HTTP/3.
// Evidence: httpsts-worked-http-server-ts-node-http-protocol-timeouts-3
// Competency: httpsts-worked-http-server-ts-node-http-protocol-timeouts-3.
// Case 5798: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: change the tenant and prove denial before repository access.
function worked_http_server_ts_node_http_protocol_timeouts_3(protocol: "http/1.1" | "h2" | "h3", headersMs: number, requestMs: number, draining: boolean): { serve: boolean; reason: string } {
  if (protocol === "h3") return { serve: false, reason: "external-http3-boundary" };
  if (headersMs <= 0 || requestMs < headersMs) {
    return { serve: false, reason: "invalid-timeout-budget" };
  }
  if (draining) return { serve: false, reason: "draining" };
  return { serve: true, reason: protocol };
}

